class Solution {
public:
    char kthCharacter(long long k, vector<int>& operations) {
        long long length = 1;
        int shift = 0;
        for (int i = operations.size() - 1; i >= 0; --i) {
            if (operations[i] == 0) {
                if (k > length) k -= length;
                length /= 2;
            } else {
                shift = (shift + 1) % 26;
                if (k > length) k -= length;
                length /= 2;
            }
        }
        return 'a' + (k - 1 + shift) % 26;
    }
};
